import { useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './Dashboard.css';


const AREA_OPTIONS = [
  'RPT Review',
  'Expense Review',
  'ICFR',
  'P2P Review',
  'Provision Review',
  'Risk and Control Self-Assessment',
  'Risk Management',
  'Customer Review',
  'GST Audit',
  'Trial Balance Review',
  'STC Trial Balance Review and Customer Review',
  'Analytical tools',
  'FSO Review',
  'TKH Audit',
  'Success factor audit',
  'Symphony audit',
  'SAP Module audit',
  'Billing review',
];

export default function Dashboard() {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const context = location.state;

  const [tab, setTab] = useState('create');
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(null);
  const [msg, setMsg] = useState({ text: '', type: '' });
  const [search, setSearch] = useState('');
const [openPersonDD, setOpenPersonDD] = useState(null);
const [personInput, setPersonInput] = useState({});
  useEffect(() => { if (!context) navigate('/select'); }, [context, navigate]);

  const showMsg = (text, type = 'success') => {
    setMsg({ text, type });
    setTimeout(() => setMsg({ text: '', type: '' }), 3000);
  };

  const fetchRows = useCallback(async () => {
    if (!context) return;
    setLoading(true);
    try {
      const res = await axios.get('/api/observations', {
        params: { company: context.company, financialYear: context.financialYear, business: context.business }
      });
      setRows(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  }, [context]);

  useEffect(() => { fetchRows(); }, [fetchRows]);

  const addRow = async () => {
  setSaving('new');
  try {
    const payload = {
      company: context.company, financialYear: context.financialYear, business: context.business,
      area: '', observation: '', managerComment: '',
      personResponsibilityAsPerAC: '', personResponsibilityEmails: '',
      personResponsible: '', personResponsibleEmails: '',
      remarks: '', attachment: '', attachmentName: '',
      status: 'Open', closingPeriod: '',
    };
    const res = await axios.post('/api/observations', payload);
    setRows(r => [...r, res.data]);
    showMsg('Row added!');
  } catch (e) { showMsg('Error adding row', 'error'); }
  finally { setSaving(null); }
};

  const updateCell = (index, field, value) => {
    setRows(r => r.map((row, i) => i === index ? { ...row, [field]: value } : row));
  };

  const buildPayload = (row) => ({
  company: context.company, financialYear: context.financialYear, business: context.business,
  area: row.area, observation: row.observation, managerComment: row.managerComment,
  personResponsibilityAsPerAC: row.personResponsibilityAsPerAC,
  personResponsibilityEmails: row.personResponsibilityEmails || '',  // ← ADD
    personResponsibleEmails: row.personResponsibleEmails || '',
  personResponsible: row.personResponsible,
  remarks: row.remarks, attachment: row.attachment, attachmentName: row.attachmentName,
  status: row.status, closingPeriod: row.closingPeriod,
});

  const saveRow = async (index) => {
    const row = rows[index];
    if (!row._id) return;
    setSaving(index);
    try {
      const res = await axios.put(`/api/observations/${row._id}`, buildPayload(row));
      setRows(r => r.map((ro, i) => i === index ? res.data : ro));
      showMsg('Saved!');
    } catch (e) { showMsg('Save failed', 'error'); }
    finally { setSaving(null); }
  };

  const handleAreaChange = async (index, value) => {
    const updated = { ...rows[index], area: value };
    setRows(r => r.map((row, i) => i === index ? updated : row));
    if (!updated._id) return;
    try {
      const res = await axios.put(`/api/observations/${updated._id}`, buildPayload(updated));
      setRows(r => r.map((ro, i) => i === index ? res.data : ro));
    } catch (e) { console.error(e); }
  };

  const handleStatusChange = async (index) => {
    const row = rows[index];
    const newStatus = row.status === 'Open' ? 'Closed' : 'Open';
    const updated = { ...row, status: newStatus };
    setRows(r => r.map((ro, i) => i === index ? updated : ro));
    if (!row._id) return;
    try {
      await axios.put(`/api/observations/${row._id}`, buildPayload(updated));
    } catch (e) { console.error(e); }
  };

  const handleAttachment = async (index, file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (e) => {
      const updated = { ...rows[index], attachment: e.target.result, attachmentName: file.name };
      setRows(r => r.map((ro, i) => i === index ? updated : ro));
      if (!updated._id) return;
      try {
        await axios.put(`/api/observations/${updated._id}`, buildPayload(updated));
        showMsg('Attachment saved!');
      } catch (err) { console.error(err); }
    };
    reader.readAsDataURL(file);
  };

  const deleteRow = async (index) => {
    const row = rows[index];
    if (!window.confirm('Delete this row?')) return;
    try {
      if (row._id) await axios.delete(`/api/observations/${row._id}`);
      setRows(r => r.filter((_, i) => i !== index));
      showMsg('Deleted');
    } catch (e) { showMsg('Error deleting', 'error'); }
  };

  if (!context) return null;

  const filtered = rows.filter(row => {
    if (!search) return true;
    const s = search.toLowerCase();
    return (
      row.area?.toLowerCase().includes(s) ||
      row.personResponsible?.toLowerCase().includes(s) ||
      row.personResponsibilityAsPerAC?.toLowerCase().includes(s) ||
      row.observation?.toLowerCase().includes(s) ||
      row.uniqueKey?.toLowerCase().includes(s) ||
      row.status?.toLowerCase().includes(s) ||
      row.closingPeriod?.includes(s)
    );
  });

  return (
    <div className="db-bg">
      {/* Header */}
      <div className="db-header">
        <div className="db-header-left">
          <div className="db-logo">AuditPro</div>
          <div className="db-context">
            <span className="ctx-chip">{context.company}</span>
            <span className="ctx-chip">{context.financialYear}</span>
            <span className="ctx-chip">{context.business}</span>
          </div>
        </div>
        <div className="db-header-right">
          <span className="db-welcome">👋 {user?.name}</span>
          <span className="db-role-tag">{user?.role}</span>
          <button onClick={() => navigate('/select')} className="db-back-btn">← Change</button>
          <button onClick={logout} className="db-logout">Logout</button>
        </div>
      </div>

      {/* Tabs */}
      <div className="db-tabs">
        <button className={`db-tab ${tab === 'create' ? 'active' : ''}`} onClick={() => setTab('create')}>📝 Create</button>
        <button className={`db-tab ${tab === 'report' ? 'active' : ''}`} onClick={() => setTab('report')}>📊 Report</button>
      </div>

      {msg.text && <div className={`db-msg ${msg.type}`}>{msg.type === 'error' ? '⚠' : '✓'} {msg.text}</div>}

      {/* CREATE TAB */}
      {tab === 'create' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Observations <span className="db-count">{rows.length} rows</span></h2>
            <div className="toolbar-right">
              <input className="search-bar" placeholder="🔍  Search by area, person, status, key..."
                value={search} onChange={e => setSearch(e.target.value)} />
              <button className="db-add-btn" onClick={addRow} disabled={saving === 'new'}>
                {saving === 'new' ? 'Adding...' : '+ Add Row'}
              </button>
            </div>
          </div>

          {loading ? <div className="db-loading">Loading...</div> : (
            <div className="db-table-wrap">
              <table className="db-table">
                <thead>
                  <tr>
                    <th className="col-sno">S.No.</th>
                    <th className="col-key">Unique Key</th>
                    <th className="col-fy">FY</th>
                    <th className="col-biz">Business</th>
                    <th className="col-area">Area</th>
                    <th className="col-obs">Observation</th>
                    <th className="col-mc">Manager Comment</th>
                    <th className="col-prac">Person Resp. (AC)</th>
                    <th className="col-pr">Person Responsible</th>
                    <th className="col-rem">Remarks & Attachment</th>
                    <th className="col-cp">Closing Period</th>
                    <th className="col-status">Status</th>
                    <th className="col-date">Created On</th>
                    <th className="col-act">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.length === 0 ? (
                    <tr><td colSpan={14} className="db-empty">{search ? 'No results.' : 'No rows yet. Click "+ Add Row".'}</td></tr>
                  ) : filtered.map((row, i) => {
                    const realIdx = rows.indexOf(row);
                    return (
                      <tr key={row._id}>
                        <td className="col-sno td-center">{i + 1}</td>
                        <td className="col-key"><span className="key-badge">{row.uniqueKey || '—'}</span></td>
                        <td className="col-fy td-chip">{context.financialYear}</td>
                        <td className="col-biz td-chip">{context.business}</td>
                        <td className="col-area">
                          <select className="cell-select" value={row.area} onChange={e => handleAreaChange(realIdx, e.target.value)}>
                            <option value="">Select</option>
                            {AREA_OPTIONS.map(a => <option key={a}>{a}</option>)}
                          </select>
                        </td>
                        <td className="col-obs">
                          <textarea className="cell-textarea" value={row.observation}
                            onChange={e => updateCell(realIdx, 'observation', e.target.value)} placeholder="Enter observation..." />
                        </td>
                        <td className="col-mc">
                          <textarea className="cell-textarea" value={row.managerComment}
                            onChange={e => updateCell(realIdx, 'managerComment', e.target.value)} placeholder="Manager comment..." />
                        </td>
                        <td className="col-prac" style={{verticalAlign:'top', paddingTop:'8px'}}>
  {/* Names */}
  <div className="tag-box">
    {(row.personResponsibilityAsPerAC || '').split(',').map(s => s.trim()).filter(Boolean).map((name, ni) => (
      <span key={ni} className="person-tag">
        {name}
        <span className="tag-remove" onClick={async () => {
          const updated = (row.personResponsibilityAsPerAC || '').split(',').map(s => s.trim()).filter(Boolean).filter((_, i) => i !== ni);
          const newVal = updated.join(', ');
          const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityAsPerAC: newVal } : ro);
          setRows(updatedRows);
          const r = updatedRows[realIdx];
          if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
        }}>×</span>
      </span>
    ))}
    <input
      className="tag-input"
      placeholder="👤 Name + Enter"
      value={personInput[`ac_${realIdx}`] || ''}
      onChange={e => setPersonInput(p => ({ ...p, [`ac_${realIdx}`]: e.target.value }))}
      onKeyDown={async e => {
        if (e.key === 'Enter') {
          e.preventDefault();
          const val = (personInput[`ac_${realIdx}`] || '').trim();
          if (!val) return;
          const existing = (row.personResponsibilityAsPerAC || '').split(',').map(s => s.trim()).filter(Boolean);
          if (existing.includes(val)) { setPersonInput(p => ({ ...p, [`ac_${realIdx}`]: '' })); return; }
          const newVal = [...existing, val].join(', ');
          const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityAsPerAC: newVal } : ro);
          setRows(updatedRows);
          setPersonInput(p => ({ ...p, [`ac_${realIdx}`]: '' }));
          const r = updatedRows[realIdx];
          if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); showMsg('Saved!'); } catch(e) { console.error(e); }
        }
        if (e.key === 'Backspace' && !personInput[`ac_${realIdx}`]) {
          const existing = (row.personResponsibilityAsPerAC || '').split(',').map(s => s.trim()).filter(Boolean);
          if (existing.length > 0) {
            existing.pop();
            const newVal = existing.join(', ');
            const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityAsPerAC: newVal } : ro);
            setRows(updatedRows);
            const r = updatedRows[realIdx];
            if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
          }
        }
      }}
    />
  </div>

  {/* Emails - alag section */}
 {/* Emails - alag section */}
<div className="email-section">
  <div className="email-section-label">📧 Reminder Emails</div>
  <div className="tag-box email-tag-box">
    {(row.personResponsibilityEmails || '').split(',').map(s => s.trim()).filter(Boolean).map((email, ei) => (
      <span key={ei} className="email-tag" title={email}>
        {email.length > 18 ? email.substring(0, 18) + '…' : email}
        <span className="tag-remove" onClick={async () => {
          const updated = (row.personResponsibilityEmails || '').split(',').map(s => s.trim()).filter(Boolean).filter((_, i) => i !== ei);
          const newVal = updated.join(', ');
          const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityEmails: newVal } : ro);
          setRows(updatedRows);
          const r = updatedRows[realIdx];
          if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
        }}>×</span>
      </span>
    ))}
    <div style={{position:'relative', flex:1}}>
      <input
        className="tag-input"
        placeholder="email + Enter"
        value={personInput[`email_${realIdx}`] || ''}
        onChange={e => setPersonInput(p => ({ ...p, [`email_${realIdx}`]: e.target.value }))}
        onKeyDown={async e => {
          if (e.key === 'Enter') {
            e.preventDefault();
            const val = (personInput[`email_${realIdx}`] || '').trim();
            if (!val || !val.includes('@')) { showMsg('Valid email daalo!', 'error'); return; }
            const existing = (row.personResponsibilityEmails || '').split(',').map(s => s.trim()).filter(Boolean);
            if (existing.includes(val)) { setPersonInput(p => ({ ...p, [`email_${realIdx}`]: '' })); return; }
            const newVal = [...existing, val].join(', ');
            const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityEmails: newVal } : ro);
            setRows(updatedRows);
            setPersonInput(p => ({ ...p, [`email_${realIdx}`]: '' }));
            const r = updatedRows[realIdx];
            if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); showMsg('Email saved! ✓'); } catch(e) { console.error(e); }
          }
          if (e.key === 'Backspace' && !personInput[`email_${realIdx}`]) {
            const existing = (row.personResponsibilityEmails || '').split(',').map(s => s.trim()).filter(Boolean);
            if (existing.length > 0) {
              existing.pop();
              const newVal = existing.join(', ');
              const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibilityEmails: newVal } : ro);
              setRows(updatedRows);
              const r = updatedRows[realIdx];
              if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
            }
          }
        }}
      />
      {/* Auto suggest based on names count */}
      {(() => {
        const names = (row.personResponsibilityAsPerAC || '').split(',').map(s => s.trim()).filter(Boolean);
        const emails = (row.personResponsibilityEmails || '').split(',').map(s => s.trim()).filter(Boolean);
        const remaining = names.length - emails.length;
        if (remaining > 0 && emails.length < names.length) {
          return (
            <div style={{fontSize:'9px', color:'#f59e0b', marginTop:'2px', fontWeight:600}}>
              ⚠ {remaining} naam ke liye email pending
            </div>
          );
        }
        if (names.length > 0 && emails.length === names.length) {
          return <div style={{fontSize:'9px', color:'#34d399', marginTop:'2px', fontWeight:600}}>✓ Sab emails added</div>;
        }
        return null;
      })()}
    </div>
  </div>
</div>
</td>
                     <td className="col-pr" style={{verticalAlign:'top', paddingTop:'9px'}}>
  {/* Names */}
  <div className="tag-box">
    {(row.personResponsible || '').split(',').map(s => s.trim()).filter(Boolean).map((name, ni) => (
      <span key={ni} className="person-tag">
        {name}
        <span className="tag-remove" onClick={async () => {
          const updated = (row.personResponsible || '').split(',').map(s => s.trim()).filter(Boolean).filter((_, i) => i !== ni);
          const newVal = updated.join(', ');
          const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsible: newVal } : ro);
          setRows(updatedRows);
          const r = updatedRows[realIdx];
          if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
        }}>×</span>
      </span>
    ))}
    <input
      className="tag-input"
      placeholder="👤 Name + Enter"
      value={personInput[`pr_${realIdx}`] || ''}
      onChange={e => setPersonInput(p => ({ ...p, [`pr_${realIdx}`]: e.target.value }))}
      onKeyDown={async e => {
        if (e.key === 'Enter') {
          e.preventDefault();
          const val = (personInput[`pr_${realIdx}`] || '').trim();
          if (!val) return;
          const existing = (row.personResponsible || '').split(',').map(s => s.trim()).filter(Boolean);
          if (existing.includes(val)) { setPersonInput(p => ({ ...p, [`pr_${realIdx}`]: '' })); return; }
          const newVal = [...existing, val].join(', ');
          const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsible: newVal } : ro);
          setRows(updatedRows);
          setPersonInput(p => ({ ...p, [`pr_${realIdx}`]: '' }));
          const r = updatedRows[realIdx];
          if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); showMsg('Saved!'); } catch(e) { console.error(e); }
        }
        if (e.key === 'Backspace' && !personInput[`pr_${realIdx}`]) {
          const existing = (row.personResponsible || '').split(',').map(s => s.trim()).filter(Boolean);
          if (existing.length > 0) {
            existing.pop();
            const newVal = existing.join(', ');
            const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsible: newVal } : ro);
            setRows(updatedRows);
            const r = updatedRows[realIdx];
            if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
          }
        }
      }}
    />
  </div>

  {/* Emails */}
  <div className="email-section">
    <div className="email-section-label">📧 Reminder Emails</div>
    <div className="tag-box email-tag-box">
      {(row.personResponsibleEmails || '').split(',').map(s => s.trim()).filter(Boolean).map((email, ei) => (
        <span key={ei} className="email-tag" title={email}>
          {email.length > 18 ? email.substring(0, 18) + '…' : email}
          <span className="tag-remove" onClick={async () => {
            const updated = (row.personResponsibleEmails || '').split(',').map(s => s.trim()).filter(Boolean).filter((_, i) => i !== ei);
            const newVal = updated.join(', ');
            const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibleEmails: newVal } : ro);
            setRows(updatedRows);
            const r = updatedRows[realIdx];
            if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
          }}>×</span>
        </span>
      ))}
      <div style={{position:'relative', flex:1}}>
        <input
          className="tag-input"
          placeholder="email + Enter"
          value={personInput[`premail_${realIdx}`] || ''}
          onChange={e => setPersonInput(p => ({ ...p, [`premail_${realIdx}`]: e.target.value }))}
          onKeyDown={async e => {
            if (e.key === 'Enter') {
              e.preventDefault();
              const val = (personInput[`premail_${realIdx}`] || '').trim();
              if (!val || !val.includes('@')) { showMsg('Valid email daalo!', 'error'); return; }
              const existing = (row.personResponsibleEmails || '').split(',').map(s => s.trim()).filter(Boolean);
              if (existing.includes(val)) { setPersonInput(p => ({ ...p, [`premail_${realIdx}`]: '' })); return; }
              const newVal = [...existing, val].join(', ');
              const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibleEmails: newVal } : ro);
              setRows(updatedRows);
              setPersonInput(p => ({ ...p, [`premail_${realIdx}`]: '' }));
              const r = updatedRows[realIdx];
              if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); showMsg('Email saved!'); } catch(e) { console.error(e); }
            }
            if (e.key === 'Backspace' && !personInput[`premail_${realIdx}`]) {
              const existing = (row.personResponsibleEmails || '').split(',').map(s => s.trim()).filter(Boolean);
              if (existing.length > 0) {
                existing.pop();
                const newVal = existing.join(', ');
                const updatedRows = rows.map((ro, i) => i === realIdx ? { ...ro, personResponsibleEmails: newVal } : ro);
                setRows(updatedRows);
                const r = updatedRows[realIdx];
                if (r._id) try { await axios.put(`/api/observations/${r._id}`, buildPayload(r)); } catch(e) { console.error(e); }
              }
            }
          }}
        />
        {(() => {
          const names = (row.personResponsible || '').split(',').map(s => s.trim()).filter(Boolean);
          const emails = (row.personResponsibleEmails || '').split(',').map(s => s.trim()).filter(Boolean);
          const remaining = names.length - emails.length;
          if (remaining > 0) return <div style={{fontSize:'9px', color:'#f59e0b', marginTop:'2px', fontWeight:600}}>⚠ {remaining} naam ke liye email pending</div>;
          if (names.length > 0 && emails.length >= names.length) return <div style={{fontSize:'9px', color:'#34d399', marginTop:'2px', fontWeight:600}}>✓ Sab emails added</div>;
          return null;
        })()}
      </div>
    </div>
  </div>
</td>
                        <td className="col-rem" style={{verticalAlign:'top', paddingTop:'9px'}}>
  <div className="remarks-box">
    <textarea
      className="remarks-textarea"
      value={row.remarks}
      onChange={e => updateCell(realIdx, 'remarks', e.target.value)}
      placeholder="Add remarks..."
    />
    <label className="remarks-attach" title={row.attachmentName || 'Attach file'}>
      <input type="file" style={{ display: 'none' }}
        onChange={e => handleAttachment(realIdx, e.target.files[0])} />
      {row.attachment ? '✓' : '📎'}
    </label>
  </div>
  {row.attachment && (
    <a className="attach-link" href={row.attachment} download={row.attachmentName}>
      ⬇ {row.attachmentName?.substring(0, 18)}
    </a>
  )}
</td>
                        <td className="col-cp">
                          <input className="cell-input" type="date" value={row.closingPeriod}
                            onChange={e => updateCell(realIdx, 'closingPeriod', e.target.value)} />
                        </td>
                        <td className="col-status">
                          <span className={`status-pill ${row.status === 'Closed' ? 'closed' : 'open'}`}
                            onClick={() => handleStatusChange(realIdx)} title="Click to toggle">
                            <span className="status-dot"></span>
                            {row.status}
                          </span>
                        </td>
                        <td className="col-date td-date">
                          {new Date(row.createdAt).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}
                        </td>
                        <td className="col-act">
                          <div className="action-btns">
                            <button className="save-btn" onClick={() => saveRow(realIdx)} disabled={saving === realIdx}>
                              {saving === realIdx ? '...' : '💾 Save'}
                            </button>
                            <button className="del-btn" onClick={() => deleteRow(realIdx)}>🗑 Del</button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* REPORT TAB */}
      {tab === 'report' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Report</h2>
            <input className="search-bar" placeholder="🔍  Search..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <div className="report-cards">
            <div className="r-card total"><div className="r-num">{rows.length}</div><div className="r-label">Total</div></div>
            <div className="r-card open"><div className="r-num">{rows.filter(r => r.status === 'Open').length}</div><div className="r-label">Open</div></div>
            <div className="r-card closed"><div className="r-num">{rows.filter(r => r.status === 'Closed').length}</div><div className="r-label">Closed</div></div>
          </div>
          <div className="db-table-wrap">
            <table className="db-table">
              <thead>
                <tr>
                  <th>S.No.</th><th>Key</th><th>FY</th><th>Business</th><th>Area</th>
                  <th>Observation</th><th>Manager Comment</th><th>Person Resp. (AC)</th>
                  <th>Person Responsible</th><th>Remarks</th><th>Closing Period</th>
                  <th>Status</th><th>Created On</th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan={13} className="db-empty">No data.</td></tr>
                ) : filtered.map((row, i) => (
                  <tr key={row._id}>
                    <td className="td-center">{i + 1}</td>
                    <td><span className="key-badge">{row.uniqueKey}</span></td>
                    <td className="td-chip">{context.financialYear}</td>
                    <td className="td-chip">{context.business}</td>
                    <td>{row.area}</td>
                    <td>{row.observation}</td>
                    <td>{row.managerComment}</td>
                    <td>{row.personResponsibilityAsPerAC}</td>
                    <td>{row.personResponsible}</td>
                    <td>{row.remarks}</td>
                    <td>{row.closingPeriod}</td>
                    <td><span className={`status-pill ${row.status === 'Closed' ? 'closed' : 'open'}`}><span className="status-dot"></span>{row.status}</span></td>
                    <td className="td-date">{new Date(row.createdAt).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
